export const 鎮宅鬼恠 = (bi) => {
    const u = bi.u, k = 2.7;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 0.7) * k + 2;
    const 線 = (書, 寬 = 0.38) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 圈 = (x, z, r = 0.28) => {
        const c = bi.ctx;
        c.save();
        c.lineWidth = 0.3 * u;
        bi.A(X(x), Z(z), r * k);
        c.restore();
    };
    // 符頭：桿＋斷桿綴圈＋散圈
    線(p => p.M(X(0.8), Z(1.0)).L(X(6.6), Z(0.9)));
    圈(7.0, 0.9);
    線(p => p.M(X(1.4), Z(2.3)).L(X(3.2), Z(2.25)));
    圈(1.1, 2.3);
    圈(3.5, 2.25);
    線(p => p.M(X(4.6), Z(2.2)).L(X(5.8), Z(2.17)));
    圈(4.3, 2.2);
    圈(6.1, 2.15);
    圈(1.2, 3.5);
    圈(4.4, 3.4);
    圈(6.9, 3.3);
    // 左密目梯（七箱）
    線(p => p.M(X(0.8), Z(4.2)).L(X(0.8), Z(18.9)));
    線(p => p.M(X(3.2), Z(4.15)).L(X(3.2), Z(18.85)));
    for (let i = 0; i <= 7; i++)
        線(p => p.M(X(0.8), Z(4.2 + i * 2.1)).L(X(3.2), Z(4.15 + i * 2.1)));
    // 中柱：蓮節・東本字形疊（摹形從簡）
    線(p => p.M(X(4.9), Z(4.3)).L(X(4.87), Z(18.5)), 0.4);
    // 蓮節（雙葉眼）
    const 節 = (z0) => {
        線(p => p.M(X(4.88), Z(z0))
            .C(X(4.3), Z(z0 + 0.4), X(4.3), Z(z0 + 1.1), X(4.88), Z(z0 + 1.5)), 0.34);
        線(p => p.M(X(4.88), Z(z0))
            .C(X(5.5), Z(z0 + 0.4), X(5.5), Z(z0 + 1.1), X(4.88), Z(z0 + 1.5)), 0.34);
    };
    節(5.4);
    節(7.2);
    // 東形（口＋乂足）
    線(p => p.M(X(4.1), Z(9.4)).L(X(5.7), Z(9.35)), 0.36);
    線(p => p.M(X(4.3), Z(9.9)).L(X(4.3), Z(11.0)).L(X(5.5), Z(10.97))
        .L(X(5.5), Z(9.87)).L(X(4.25), Z(9.9)), 0.34);
    線(p => p.M(X(4.3), Z(11.4)).C(X(4.0), Z(12.0), X(3.8), Z(12.5), X(3.7), Z(12.9)), 0.34);
    線(p => p.M(X(5.5), Z(11.4)).C(X(5.8), Z(12.0), X(6.0), Z(12.5), X(6.1), Z(12.9)), 0.34);
    // 本形（十＋乂）
    線(p => p.M(X(4.0), Z(13.6)).L(X(5.8), Z(13.55)), 0.36);
    線(p => p.M(X(4.2), Z(14.5)).C(X(4.5), Z(14.9), X(5.2), Z(15.2), X(5.8), Z(15.3)), 0.32);
    線(p => p.M(X(5.6), Z(14.4)).C(X(5.2), Z(14.9), X(4.6), Z(15.3), X(4.1), Z(15.5)), 0.32);
    // 底日
    線(p => p.M(X(4.2), Z(16.2)).L(X(4.2), Z(18.2)).L(X(5.6), Z(18.15))
        .L(X(5.6), Z(16.15)).L(X(4.15), Z(16.2)), 0.34);
    線(p => p.M(X(4.3), Z(17.2)).L(X(5.5), Z(17.17)), 0.3);
    // 右軌＋田箱＋底目
    線(p => p.M(X(6.8), Z(4.3)).L(X(6.8), Z(19.0)));
    線(p => p.M(X(6.0), Z(6.4)).L(X(6.75), Z(6.37)), 0.32);
    線(p => p.M(X(6.0), Z(10.8)).L(X(6.75), Z(10.77)), 0.32);
    線(p => p.M(X(6.0), Z(15.2)).L(X(6.75), Z(15.17)), 0.32);
};
